#include <SPI.h>
#include <MFRC522.h>

#define SS_PIN  10
#define RST_PIN 9

MFRC522 rfid(SS_PIN, RST_PIN);

void setup() {
  Serial.begin(9600);
  SPI.begin();
  rfid.PCD_Init();
  Serial.println("=== UID Scanner ===");
  Serial.println("Tap a card to read its UID...");
}

void loop() {
  if (!rfid.PICC_IsNewCardPresent()) return;
  if (!rfid.PICC_ReadCardSerial())  return;

  Serial.print("UID: ");
  for (byte i = 0; i < rfid.uid.size; i++) {
    // Print with leading zero so each byte is 2 hex digits
    if (rfid.uid.uidByte[i] < 0x10) Serial.print("0");
    Serial.print(rfid.uid.uidByte[i], HEX);
    Serial.print(" ");
  }
  Serial.println();
  Serial.println("Copy these bytes into your smart lock code!");
  Serial.println("---");

  rfid.PICC_HaltA();
  delay(1000);
}

#include <SPI.h>
#include <MFRC522.h>
#include <Wire.h>
#include <LiquidCrystal_I2C.h>
#include <Servo.h>

// ── PIN DEFINITIONS ───────────────────────────────
#define SS_PIN     10
#define RST_PIN    9
#define RELAY_PIN  7
#define GREEN_PIN  4
#define RED_PIN    5
#define BUZZER_PIN 8
#define SERVO_PIN  6

// ── OBJECTS ───────────────────────────────────────
MFRC522 rfid(SS_PIN, RST_PIN);
LiquidCrystal_I2C lcd(0x27, 16, 2);
Servo doorServo;

// ── AUTHORIZED CARD WHITELIST ─────────────────────
// Replace with YOUR card UIDs from Step 1!
struct AuthCard {
  byte uid[4];
  String name;
};

AuthCard authorized[] = {
  { {0xA1, 0xB2, 0xC3, 0xD4}, "Jason"  },
  { {0x12, 0x34, 0x56, 0x78}, "Priya"  },
  { {0xDE, 0xAD, 0xBE, 0xEF}, "Arjun"  }
};

int authCount = sizeof(authorized) / sizeof(authorized[0]);

// ── SETUP ─────────────────────────────────────────
void setup() {
  Serial.begin(9600);
  SPI.begin();
  rfid.PCD_Init();

  pinMode(RELAY_PIN,  OUTPUT);
  pinMode(GREEN_PIN,  OUTPUT);
  pinMode(RED_PIN,    OUTPUT);
  pinMode(BUZZER_PIN, OUTPUT);

  // Relay OFF = door locked (HIGH = relay inactive for most modules)
  digitalWrite(RELAY_PIN, HIGH);
  digitalWrite(GREEN_PIN, LOW);
  digitalWrite(RED_PIN,   LOW);

  doorServo.attach(SERVO_PIN);
  doorServo.write(0);   // 0° = locked position

  lcd.init();
  lcd.backlight();
  lcd.setCursor(0, 0);
  lcd.print("  Smart Lock  ");
  lcd.setCursor(0, 1);
  lcd.print(" Tap your card");
  Serial.println("Smart Lock ready. Tap a card...");
}

// ── HELPERS ───────────────────────────────────────
bool isAuthorized(byte* tappedUID, String &ownerName) {
  for (int i = 0; i < authCount; i++) {
    bool match = true;
    for (byte j = 0; j < 4; j++) {
      if (authorized[i].uid[j] != tappedUID[j]) {
        match = false;
        break;
      }
    }
    if (match) {
      ownerName = authorized[i].name;
      return true;
    }
  }
  return false;
}

void grantAccess(String name) {
  Serial.println("✅ ACCESS GRANTED: " + name);

  // LCD
  lcd.clear();
  lcd.setCursor(0, 0);
  lcd.print("Access Granted!");
  lcd.setCursor(0, 1);
  lcd.print("Welcome, " + name + "!");

  // Green LED ON
  digitalWrite(GREEN_PIN, HIGH);

  // Relay ON → unlocks electronic lock
  digitalWrite(RELAY_PIN, LOW);   // LOW = relay active (most modules)

  // Servo swings to 90° → door opens
  doorServo.write(90);

  delay(3000);   // Door stays open 3 seconds

  // Auto-lock
  doorServo.write(0);
  digitalWrite(RELAY_PIN, HIGH);
  digitalWrite(GREEN_PIN, LOW);

  lcd.clear();
  lcd.print(" Tap your card");
}

void denyAccess() {
  Serial.println("❌ ACCESS DENIED — Unknown card.");

  // LCD
  lcd.clear();
  lcd.setCursor(0, 0);
  lcd.print(" Access Denied!");
  lcd.setCursor(0, 1);
  lcd.print("Unknown User!  ");

  // Red LED + Buzzer (3 short beeps)
  for (int i = 0; i < 3; i++) {
    digitalWrite(RED_PIN,    HIGH);
    digitalWrite(BUZZER_PIN, HIGH);
    delay(200);
    digitalWrite(RED_PIN,    LOW);
    digitalWrite(BUZZER_PIN, LOW);
    delay(150);
  }

  delay(1500);
  lcd.clear();
  lcd.print(" Tap your card");
}

// ── MAIN LOOP ─────────────────────────────────────
void loop() {
  if (!rfid.PICC_IsNewCardPresent()) return;
  if (!rfid.PICC_ReadCardSerial())  return;

  byte tappedUID[4];
  for (byte i = 0; i < 4; i++) {
    tappedUID[i] = rfid.uid.uidByte[i];
  }

  String ownerName = "";
  if (isAuthorized(tappedUID, ownerName)) {
    grantAccess(ownerName);
  } else {
    denyAccess();
  }

  rfid.PICC_HaltA();
  rfid.PCD_StopCrypto1();
}

/*
  RELAY CONCEPT:
  A relay is an electrically controlled switch.
  Arduino's pin (5V, tiny current) controls
  an electromagnet inside the relay that physically
  snaps a bigger switch — which can handle
  higher currents (like a door lock solenoid).

  Most relay modules are ACTIVE LOW:
    digitalWrite(RELAY_PIN, LOW)  → relay ON  (click! circuit closes)
    digitalWrite(RELAY_PIN, HIGH) → relay OFF (circuit opens)

  The relay has 3 screw terminals:
    COM = Common (always connected)
    NO  = Normally Open   (open until relay triggers)
    NC  = Normally Closed (closed until relay triggers)

  For a door lock: wire COM and NO.
  When relay triggers → COM and NO connect → lock releases.
*/

#define RELAY_PIN 7

void setup() {
  pinMode(RELAY_PIN, OUTPUT);
  digitalWrite(RELAY_PIN, HIGH);  // Start OFF (door locked)
  Serial.begin(9600);
}

void loop() {
  Serial.println("Relay ON  → CLICK → door unlocks");
  digitalWrite(RELAY_PIN, LOW);   // Relay ON
  delay(3000);

  Serial.println("Relay OFF → door locks again");
  digitalWrite(RELAY_PIN, HIGH);  // Relay OFF
  delay(3000);
}

#include <Servo.h>

Servo doorServo;

/*
  SERVO CONCEPT:
  A servo motor rotates to a specific ANGLE (0° to 180°).
  We use it to physically push/pull a door model.

  doorServo.write(0)   → 0°  = locked position
  doorServo.write(90)  → 90° = door fully open
  doorServo.write(45)  → 45° = half open

  In the smart lock:
  - Authorized card  → write(90) → door opens
  - After 3 seconds  → write(0)  → door closes (auto-lock)
*/

void setup() {
  doorServo.attach(6);    // Servo signal wire → Pin 6
  Serial.begin(9600);
}

void loop() {
  Serial.println("Door LOCKED (0 degrees)");
  doorServo.write(0);
  delay(2000);

  Serial.println("Door OPEN (90 degrees)");
  doorServo.write(90);
  delay(2000);

  Serial.println("Door HALF OPEN (45 degrees)");
  doorServo.write(45);
  delay(2000);
}
